/**
 * Get confidence thresholds
 */
private getConfidenceThresholds(): ConfidenceThresholds {
  return this.config.processingConfig.confidenceThresholds;
}

/**
 * Extract configuration for AI routing stage
 */
private getAIRoutingConfig(): AIRoutingConfig {
  return {
    settings: {
      aiRouting: this.config.processingConfig.settings.aiRouting,
    },
    confidenceThresholds: this.config.processingConfig.confidenceThresholds,
  };
}

/**
 * Extract configuration for AI feature extraction stage
 */
private getAIFeatureExtractionConfig(): AIFeatureExtractionConfig {
  const openaiApiKey = process.env.OPENAI_API_KEY || '';
  if (!openaiApiKey) {
    throw new Error('OPENAI_API_KEY environment variable is required for AI feature extraction');
  }

  return {
    openai: {
      apiKey: openaiApiKey,
      model: 'gpt-4o-mini',
      temperature: 0.0,
      responseFormat: 'json_schema',
    },
    prompts: this.config.processingConfig.aiPrompts.featureExtraction,
    featureExtractionSchema: {
      name: 'email_feature_extraction',
      description: 'Extract semantic features from email content',
      schema: this.config.processingConfig.featureExtractionSchema as unknown as Record<string, unknown>,
      strict: true,
    },
    retryPolicy: {
      maxRetries: 3,
      backoffMs: 1000,
    },
  };
}

