     1→/**
     2→ * AI Feature Extraction Stage
     3→ *
     4→ * Stage 8a of the EmailCategorizer pipeline. Uses LangChain OpenAI integration with GPT-4o-mini
     5→ * for semantic feature extraction with JSON schema validation and batch processing support.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Calling OpenAI API with structured prompts and email content
     9→ * - Validating AI responses against JSON schema
    10→ * - Extracting semantic intent and category enhancements
    11→ * - Validating evidence grounding (quoted phrases must exist in email)
    12→ * - Providing retry logic and error handling for API failures
    13→ * - Supporting batch processing with concurrent API calls
    14→ */
    15→
    16→import Ajv from 'ajv';
    17→import { OpenAI } from 'openai';
    18→import { ClassificationSession, EmailMessage } from '../types';
    19→import { ClassificationResult, CandidateScore } from '../types/classification-result';
    20→import { AttributeContext } from '../types/attribute-context';
    21→import {
    22→  formatEmailAddress,
    23→  formatObjectForTemplate,
    24→  getEmailBodyText,
    25→  interpolateTemplate,
    26→} from '../utils/template-utils';
    27→
    28→// Configuration interface for AI feature extraction
    29→export interface AIFeatureExtractionConfig {
    30→  openai: {
    31→    apiKey: string;
    32→    model: string;
    33→    temperature: number;
    34→    responseFormat: 'json_schema' | 'json_object'; // Support both for backward compatibility
    35→  };
    36→  prompts: {
    37→    systemPrompt: string[];
    38→    userPrompt: string[];
    39→  };
    40→  featureExtractionSchema: {
    41→    name?: string;
    42→    description?: string;
    43→    schema: Record<string, unknown>;
    44→    strict?: boolean;
    45→  };
    46→  retryPolicy: {
    47→    maxRetries: number;
    48→    backoffMs: number;
    49→  };
    50→}
    51→
    52→// Semantic intent extracted by AI
    53→export interface SemanticIntent {
    54→  primaryPurpose: 'notification' | 'request' | 'update' | 'alert';
    55→  actionRequired: 'none' | 'view' | 'respond' | 'complete';
    56→  urgencyLevel: 'none' | 'low' | 'medium' | 'high';
    57→}
    58→
    59→// Evidence structure for category enhancements
    60→export interface CategoryEvidence {
    61→  quotedPhrases: string[];
    62→  keywords: string[];
    63→  reasoning: string;
    64→}
    65→
    66→// Category enhancement from AI analysis
    67→export interface CategoryEnhancement {
    68→  applies: boolean;
    69→  confidenceBoost: number;
    70→  evidence: CategoryEvidence;
    71→}
    72→
    73→// Complete feature extraction result from AI
    74→export interface FeatureExtractionData {
    75→  semanticIntent: SemanticIntent;
    76→  categoryEnhancements: Record<string, CategoryEnhancement>;
    77→}
    78→
    79→// Evidence validation result
    80→export interface EvidenceValidation {
    81→  validPhrases: string[];
    82→  invalidPhrases: string[];
    83→  fabricationDetected: boolean;
    84→}
    85→
    86→// Complete stage result interface
    87→export interface FeatureExtractionResult {
    88→  featureExtraction: FeatureExtractionData;
    89→  validationPassed: boolean;
    90→  validationErrors: string[];
    91→  evidenceValidation: EvidenceValidation;
    92→  processingDurationMs: number;
    93→  tokenUsage: number;
    94→  apiCallCount: number;
    95→  retryCount: number;
    96→}
    97→
    98→/**
    99→ * AI Feature Extraction Stage Implementation
   100→ *
   101→ * Integrates with OpenAI GPT-4o-mini to extract semantic features and enhance
   102→ * category classifications with evidence-grounded analysis.
   103→ *
   104→ * CANONICAL SIGNATURE: (email, session, result, config) => Promise<void>
   105→ * Mutates result object by storing feature extraction data in explainabilityTrace
   106→ */
   107→export async function aiFeatureExtractionStage(
   108→  email: EmailMessage,
   109→  session: ClassificationSession,
   110→  result: ClassificationResult,
   111→  config: AIFeatureExtractionConfig
   112→): Promise<void> {
   113→  const startTime = Date.now();
   114→  let retryCount = 0;
   115→  let apiCallCount = 0;
   116→
   117→  // Validate inputs
   118→  validateInputs(email, session, result, config);
   119→
   120→  // Extract candidate categories and detected attributes from result
   121→  const candidateCategories = result.candidateScores;
   122→  const detectedAttributes = result.attributeContext;
   123→
   124→  // Initialize OpenAI client
   125→  const openai = new OpenAI({
   126→    apiKey: config.openai.apiKey,
   127→  });
   128→
   129→  // Setup JSON schema validator (only used for legacy json_object mode)
   130→  const ajv = new Ajv();
   131→  const validateSchema = ajv.compile(config.featureExtractionSchema.schema);
   132→
   133→  // Retry loop for API calls
   134→  let lastError: Error | null = null;
   135→
   136→  while (retryCount < config.retryPolicy.maxRetries) {
   137→    try {
   138→      apiCallCount++;
   139→
   140→      // Prepare prompts with email content interpolation
   141→      const systemPrompt = config.prompts.systemPrompt.join('\n');
   142→      const userPrompt = interpolateUserPrompt(
   143→        config.prompts.userPrompt,
   144→        email,
   145→        candidateCategories,
   146→        detectedAttributes
   147→      );
   148→
   149→      // Prepare response format based on configuration
   150→      const responseFormat =
   151→        config.openai.responseFormat === 'json_schema'
   152→          ? {
   153→              type: 'json_schema' as const,
   154→              json_schema: {
   155→                name: config.featureExtractionSchema.name || 'featureExtraction',
   156→                description:
   157→                  config.featureExtractionSchema.description ||
   158→                  'Extract semantic features and category enhancements from email content',
   159→                schema: config.featureExtractionSchema.schema,
   160→                strict: config.featureExtractionSchema.strict ?? true,
   161→              },
   162→            }
   163→          : { type: 'json_object' as const }; // Backward compatibility
   164→
   165→      // Call OpenAI API with structured outputs
   166→      const response = await openai.chat.completions.create({
   167→        model: config.openai.model,
   168→        temperature: config.openai.temperature,
   169→        response_format: responseFormat,
   170→        messages: [
   171→          { role: 'system', content: systemPrompt },
   172→          { role: 'user', content: userPrompt },
   173→        ],
   174→      });
   175→
   176→      // Parse and validate response
   177→      const rawContent = response.choices[0].message.content;
   178→      if (!rawContent) {
   179→        throw new Error('Empty response from OpenAI');
   180→      }
   181→
   182→      let featureExtractionData: FeatureExtractionData;
   183→      try {
   184→        featureExtractionData = JSON.parse(rawContent);
   185→      } catch {
   186→        throw new Error('Invalid JSON response from OpenAI');
   187→      }
   188→
   189→      // Schema validation: For structured outputs, OpenAI enforces the schema.
   190→      // For backward compatibility with json_object mode, we still validate with AJV.
   191→      const validationErrors: string[] = [];
   192→      let validationPassed = true;
   193→
   194→      if (config.openai.responseFormat === 'json_object') {
   195→        // Only validate with AJV for legacy json_object mode
   196→        validationPassed = validateSchema(featureExtractionData);
   197→
   198→        if (!validationPassed && validateSchema.errors) {
   199→          for (const error of validateSchema.errors) {
   200→            validationErrors.push(`${error.instancePath} ${error.message}`);
   201→          }
   202→          throw new Error('Schema validation failed: ' + validationErrors.join(', '));
   203→        }
   204→      }
   205→      // For json_schema mode, OpenAI has already enforced the schema, so no additional validation needed
   206→
   207→      // Validate evidence grounding
   208→      const evidenceValidation = validateEvidenceGrounding(email, featureExtractionData);
   209→
   210→      // Mutate result in place - store feature extraction data
   211→      const featureExtractionResult: FeatureExtractionResult = {
   212→        featureExtraction: featureExtractionData,
   213→        validationPassed: true,
   214→        validationErrors: [],
   215→        evidenceValidation,
   216→        processingDurationMs: Date.now() - startTime,
   217→        tokenUsage: response.usage?.total_tokens || 0,
   218→        apiCallCount,
   219→        retryCount,
   220→      };
   221→
   222→      // Defensive check for explainabilityTrace initialization
   223→      if (!result.explainabilityTrace) {
   224→        throw new Error('CRITICAL: explainabilityTrace is not initialized in result object');
   225→      }
   226→
   227→      // Initialize explainabilityTrace.aiRouting if not exists
   228→      if (!result.explainabilityTrace.aiRouting) {
   229→        result.explainabilityTrace.aiRouting = {
   230→          routingDecision: 'featureExtraction',
   231→          highConfidenceThreshold: 0,
   232→          aiRequiredThreshold: 0,
   233→          skipConditions: [],
   234→          reason: 'AI routing decision made in stage: ai-feature-extraction',
   235→        };
   236→      }
   237→
   238→      // Store feature extraction data in aiResponse.extractedFeatures
   239→      if (!result.explainabilityTrace.aiRouting.aiResponse) {
   240→        result.explainabilityTrace.aiRouting.aiResponse = {
   241→          extractedFeatures: featureExtractionData,
   242→          confidence: 0,
   243→          reasoning: 'Feature extraction completed successfully',
   244→        };
   245→      } else {
   246→        result.explainabilityTrace.aiRouting.aiResponse.extractedFeatures = featureExtractionData;
   247→      }
   248→
   249→      // Track processing time
   250→      result.explainabilityTrace.stageTimings = result.explainabilityTrace.stageTimings || {};
   251→      result.explainabilityTrace.stageTimings['aiFeatureExtraction'] = featureExtractionResult.processingDurationMs;
   252→
   253→      return;
   254→    } catch (error) {
   255→      lastError = error as Error;
   256→      retryCount++;
   257→
   258→      if (retryCount < config.retryPolicy.maxRetries) {
   259→        // Wait before retry with exponential backoff
   260→        await new Promise((resolve) => setTimeout(resolve, config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1)));
   261→      }
   262→    }
   263→  }
   264→
   265→  // All retries exhausted
   266→  throw new Error(`AI feature extraction failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
   267→}
   268→
   269→/**
   270→ * Validate input parameters
   271→ */
   272→function validateInputs(
   273→  email: EmailMessage,
   274→  session: ClassificationSession,
   275→  result: ClassificationResult,
   276→  config: AIFeatureExtractionConfig
   277→): void {
   278→  if (!email?.id && !('gmailId' in email)) {
   279→    throw new Error('Invalid email input: id or gmailId is required');
   280→  }
   281→
   282→  // Allow missing subjects but log a warning - production emails might legitimately have empty subjects
   283→  if (!email.subject) {
   284→    console.warn(`Email ${email.id} has missing subject, proceeding with empty subject for classification`);
   285→  }
   286→
   287→  if (!session?.id && !('sessionId' in session)) {
   288→    throw new Error('Invalid session input: id or sessionId is required');
   289→  }
   290→
   291→  if (!result) {
   292→    throw new Error('Classification result is required');
   293→  }
   294→
   295→  if (!result.candidateScores || typeof result.candidateScores !== 'object') {
   296→    throw new Error('Candidate scores are required in result and must be an object');
   297→  }
   298→
   299→  if (!result.attributeContext || typeof result.attributeContext !== 'object') {
   300→    throw new Error('Attribute context is required in result and must be an object');
   301→  }
   302→
   303→  // Validate candidateScores structure
   304→  for (const [category, scoreData] of Object.entries(result.candidateScores)) {
   305→    if (!scoreData || typeof scoreData !== 'object') {
   306→      throw new Error(`Invalid candidate score for category ${category}: must be an object`);
   307→    }
   308→    if (typeof scoreData.score !== 'number') {
   309→      throw new Error(`Invalid candidate score for category ${category}: score must be a number`);
   310→    }
   311→  }
   312→
   313→  if (!config) {
   314→    throw new Error('Configuration is required');
   315→  }
   316→
   317→  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
   318→    throw new Error('Invalid configuration: OpenAI API key is required');
   319→  }
   320→
   321→  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
   322→    throw new Error('Invalid configuration: system and user prompts are required');
   323→  }
   324→
   325→  if (!config.featureExtractionSchema) {
   326→    throw new Error('Invalid configuration: feature extraction schema is required');
   327→  }
   328→}
   329→
   330→/**
   331→ * Interpolate user prompt template with email content and analysis data
   332→ *
   333→ * Supports dynamic object path resolution with these placeholders:
   334→ * - {email.from} - formatted email address
   335→ * - {email.subject} - email subject
   336→ * - {email.body} - email body text
   337→ * - {candidateCategories} - JSON formatted candidate categories
   338→ * - {detectedAttributes} - JSON formatted detected attributes
   339→ */
   340→function interpolateUserPrompt(
   341→  userPromptTemplate: string[],
   342→  email: EmailMessage,
   343→  candidateCategories: Record<string, CandidateScore>,
   344→  detectedAttributes: AttributeContext
   345→): string {
   346→  const template = userPromptTemplate.join('\n');
   347→
   348→  // Create interpolation context with all available data
   349→  const context = {
   350→    email: {
   351→      from: formatEmailAddress(email.from),
   352→      subject: email.subject || '',
   353→      body: getEmailBodyText(email),
   354→    },
   355→    candidateCategories: formatObjectForTemplate(candidateCategories as unknown as Record<string, unknown>),
   356→    detectedAttributes: formatObjectForTemplate(detectedAttributes as unknown as Record<string, unknown>),
   357→  };
   358→
   359→  // Perform template interpolation using dynamic path resolution
   360→  return interpolateTemplate(template, context);
   361→}
   362→
   363→/**
   364→ * Validate that quoted phrases in evidence actually exist in the email content
   365→ */
   366→function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
   367→  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
   368→  const validPhrases: string[] = [];
   369→  const invalidPhrases: string[] = [];
   370→
   371→  // Check all quoted phrases in category enhancements
   372→  for (const [, enhancement] of Object.entries(featureExtraction.categoryEnhancements || {})) {
   373→    if (enhancement.evidence?.quotedPhrases) {
   374→      for (const phrase of enhancement.evidence.quotedPhrases) {
   375→        const normalizedPhrase = phrase.toLowerCase().trim();
   376→        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
   377→          validPhrases.push(phrase);
   378→        } else if (normalizedPhrase) {
   379→          invalidPhrases.push(phrase);
   380→        }
   381→      }
   382→    }
   383→  }
